9012	\begin{lemma}
9013	[Local vanishing of the evaluated augmented {\v C}ech homology]
9014	  \label{lem:cechSection_isZero_homology}
9015	  \lean{AlgebraicGeometry.cechSection_isZero_homology}
9016	  \uses{lem:cechSection_complex_iso, lem:cechSection_contractible,
9017	    lem:isZero_homology_of_homotopy_id_zero}
9018	  Let \(V \le \operatorname{coverOpen}\mathcal{U}\,i\) for some index \(i\). Then for every
9019	  degree \(p\) the homology \(H^p(D^\bullet)\) of the augmented {\v C}ech complex evaluated at
9020	  \(V\) (the complex \(D^\bullet\) of Lemma~\ref{lem:cechSection_complex_iso}) is a zero
9021	  object; equivalently \(D^\bullet\) carries a contracting homotopy \(\mathrm{id}_{D^\bullet}
9022	  \simeq 0\). This is the residual obligation of Step~3 of
9023	  Lemma~\ref{lem:cech_augmented_resolution}.
9024	\end{lemma}
9025	\begin{proof}
9026	  \uses{lem:cechSection_complex_iso, lem:cechSection_contractible,
9027	    lem:isZero_homology_of_homotopy_id_zero}
9028	  By Lemma~\ref{lem:cechSection_complex_iso} the evaluated complex \(D^\bullet\) is
9029	  isomorphic to the augmented concrete section {\v C}ech complex \(D'^\bullet_{\mathrm{aug}}\).
9030	  The hypothesis \(V \le \operatorname{coverOpen}\mathcal{U}\,i\) places \(V\) inside one cover
9031	  member, so Lemma~\ref{lem:cechSection_contractible} gives a contracting homotopy
9032	  \(\mathrm{id}_{D'^\bullet_{\mathrm{aug}}} \simeq 0\); transporting it across the complex
9033	  isomorphism yields \(\mathrm{id}_{D^\bullet} \simeq 0\).
9034	  Lemma~\ref{lem:isZero_homology_of_homotopy_id_zero} then makes
9035	  \(H^p(D^\bullet)\) a zero object in every degree.
9036	\end{proof}
