9040	\begin{lemma}[Pushforward sections are sections over the preimage]
9041	  \label{lem:pushforward_obj_obj_mathlib}
9042	  \lean{AlgebraicGeometry.Scheme.Modules.pushforward_obj_obj}
9043	  \mathlibok
9044	  \textit{Provided by Mathlib.}
9045	  For a morphism \(f : X \to Y\), an \(\mathcal{O}_X\)-module \(\mathcal{M}\), and an open
9046	  \(U \subseteq Y\), the sections of the pushforward \(f_*\mathcal{M}\) over \(U\) coincide
9047	  definitionally with the sections of \(\mathcal{M}\) over the preimage:
9048	  \(\Gamma(U, f_*\mathcal{M}) = \Gamma(f^{-1}(U), \mathcal{M})\).
